import{_ as e,c as i,o as l,$ as s}from"./chunks/framework.ByJNblvT.js";const k=JSON.parse('{"title":"🙋 常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md","lastUpdated":1774623019000}'),d={name:"guide/faq.md"};function r(t,a,c,o,n,h){return l(),i("div",null,[...a[0]||(a[0]=[s(`<h1 id="🙋-常见问题" tabindex="-1">🙋 常见问题 <a class="header-anchor" href="#🙋-常见问题" aria-label="Permalink to “🙋 常见问题”">​</a></h1><h2 id="初始化图表后-只能看到一条线-是怎么回事" tabindex="-1">初始化图表后，只能看到一条线，是怎么回事？ <a class="header-anchor" href="#初始化图表后-只能看到一条线-是怎么回事" aria-label="Permalink to “初始化图表后，只能看到一条线，是怎么回事？”">​</a></h2><p>图表总是会填充容器，检查一下容器是否有高度。</p><h2 id="蜡烛柱显示趋近于一条线-看不到波动-怎么办" tabindex="-1">蜡烛柱显示趋近于一条线，看不到波动，怎么办？ <a class="header-anchor" href="#蜡烛柱显示趋近于一条线-看不到波动-怎么办" aria-label="Permalink to “蜡烛柱显示趋近于一条线，看不到波动，怎么办？”">​</a></h2><p>在设置交易对的时候要设置精度，调用<code>setSymbol({ ticker: &#39;TestSymbol&#39;, pricePrecision: 6, volumePrecision: 6 })</code>。</p><h2 id="分时图怎么创建" tabindex="-1">分时图怎么创建？ <a class="header-anchor" href="#分时图怎么创建" aria-label="Permalink to “分时图怎么创建？”">​</a></h2><p>通过样式设置。</p><div class="language-javascript"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">chart.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setStyles</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  candle: {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    type: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;area&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">});</span></span></code></pre></div><h2 id="内置的技术指标-计算出来的数据不是想要的-怎么办" tabindex="-1">内置的技术指标，计算出来的数据不是想要的，怎么办？ <a class="header-anchor" href="#内置的技术指标-计算出来的数据不是想要的-怎么办" aria-label="Permalink to “内置的技术指标，计算出来的数据不是想要的，怎么办？”">​</a></h2><p>可以通过图表方法<code>createIndicator</code>或者<code>overrideIndicator</code>重写<code>calc</code>即可。</p><h2 id="想创建一个内置技术指标之外的指标-怎么办" tabindex="-1">想创建一个内置技术指标之外的指标，怎么办？ <a class="header-anchor" href="#想创建一个内置技术指标之外的指标-怎么办" aria-label="Permalink to “想创建一个内置技术指标之外的指标，怎么办？”">​</a></h2><p>图表支持自定义技术指标，详情参阅<a href="/guide/indicator">技术指标</a>。</p><h2 id="想标记一下买卖点-该怎么做" tabindex="-1">想标记一下买卖点，该怎么做？ <a class="header-anchor" href="#想标记一下买卖点-该怎么做" aria-label="Permalink to “想标记一下买卖点，该怎么做？”">​</a></h2><p>可以使用覆盖物，内置的覆盖物有一个<code>simpleAnnotation</code>，用图表api创建即可<code>createOverlay({ name: &#39;simpleAnnotation&#39;, ... })</code>。</p><h2 id="图表为什么完全没有数据" tabindex="-1">图表为什么完全没有数据？ <a class="header-anchor" href="#图表为什么完全没有数据" aria-label="Permalink to “图表为什么完全没有数据？”">​</a></h2><p>优先检查下面几项：</p><ul><li><code>getBars</code> 是否真的调用了 <code>callback(data)</code></li><li><code>setSymbol(...)</code> 和 <code>setPeriod(...)</code> 是否已设置</li><li>返回的数据是否符合 <code>KLineData[]</code> 结构</li><li><code>timestamp</code> 是否是毫秒级时间戳</li></ul><p>详情可以参阅<a href="/guide/data-integration">数据接入</a>。</p><h2 id="实时数据为什么没有更新" tabindex="-1">实时数据为什么没有更新？ <a class="header-anchor" href="#实时数据为什么没有更新" aria-label="Permalink to “实时数据为什么没有更新？”">​</a></h2><p>通常是以下原因之一：</p><ul><li><code>subscribeBar</code> 中没有调用 <code>callback(bar)</code></li><li>推送的不是单根 <code>KLineData</code></li><li>最新数据的 <code>timestamp</code> 小于当前最后一根</li><li>切换交易对或周期后，旧订阅没有正确释放</li></ul><h2 id="为什么会出现重复-k-线" tabindex="-1">为什么会出现重复 K 线？ <a class="header-anchor" href="#为什么会出现重复-k-线" aria-label="Permalink to “为什么会出现重复 K 线？”">​</a></h2><p>一般是分页边界处理不一致，或者后端返回了重复时间戳的数据。建议在进入 <code>callback(...)</code> 前先做排序和去重。</p><h2 id="为什么切换交易对或周期后-旧数据还在闪动" tabindex="-1">为什么切换交易对或周期后，旧数据还在闪动？ <a class="header-anchor" href="#为什么切换交易对或周期后-旧数据还在闪动" aria-label="Permalink to “为什么切换交易对或周期后，旧数据还在闪动？”">​</a></h2><p>通常是旧的实时订阅没有在 <code>unsubscribeBar</code> 中正确释放。建议维护订阅句柄，并在切换或销毁时及时关闭。</p><h2 id="时间显示不对-是时区问题还是时间戳问题" tabindex="-1">时间显示不对，是时区问题还是时间戳问题？ <a class="header-anchor" href="#时间显示不对-是时区问题还是时间戳问题" aria-label="Permalink to “时间显示不对，是时区问题还是时间戳问题？”">​</a></h2><p>这两个问题都很常见：</p><ul><li>如果时间整体偏移，优先检查是否需要设置 <code>setTimezone(...)</code></li><li>如果只有部分数据异常，优先检查时间戳是否误传成秒级</li></ul><h2 id="为什么指标数值不对" tabindex="-1">为什么指标数值不对？ <a class="header-anchor" href="#为什么指标数值不对" aria-label="Permalink to “为什么指标数值不对？”">​</a></h2><p>除了计算逻辑本身，还要检查输入数据字段是否完整。</p><p>例如：</p><ul><li>大部分指标依赖 <code>open / high / low / close / volume</code></li><li><code>EMV</code> 和 <code>AVP</code> 还依赖 <code>turnover</code></li></ul><h2 id="为什么样式改了没有生效" tabindex="-1">为什么样式改了没有生效？ <a class="header-anchor" href="#为什么样式改了没有生效" aria-label="Permalink to “为什么样式改了没有生效？”">​</a></h2><p>建议依次检查：</p><ul><li>是在初始化时传了 <code>styles</code>，还是运行时调用了 <code>setStyles(...)</code></li><li>传入的是增量配置，还是误把层级写错了</li><li>是否被后续代码再次覆盖</li></ul><p>详情参阅<a href="/guide/styles">样式配置</a>。</p>`,36)])])}const b=e(d,[["render",r]]);export{k as __pageData,b as default};
